import 'dart:io'; import 'package:injectable/injectable.dart'; import 'package:path_provider/path_provider.dart'; import '../../../core/utils/app_logger.dart'; @injectable class DownloadManager { Future<String?> save(String fileName, List<int> data) async { try { final dir = await getApplicationDocumentsDirectory(); final path = '${dir.path}/GooglePro/Downloads/$fileName'; final file = File(path); await file.parent.create(recursive: true); await file.writeAsBytes(data); AppLogger.info('Saved: $path'); return path; } catch (e) { AppLogger.error('Save failed', e); return null; } } Future<bool> fileExists(String path) => File(path).exists(); }